message.content:
Generate the complete installed_plugins.json file by merging the existing official plugins with the new wshobson agents plugins.

Read the current file:
cat ~/.claude/plugins/installed_plugins.json

Then generate a new version that includes ALL existing entries PLUS all 72 wshobson plugins.

Use this script to generate the merged file:

```bash
# Get all plugin names from wshobson
COMMIT="ade0c7a211d04fa1354d10359737cace5c6fc5b0"
NOW="2026-02-24T22:00:00.000Z"

# Start building the new JSON using node
node -e "
const fs = require('fs');
const path = require('path');

// Read existing
const existing = JSON.parse(fs.readFileSync(path.join(process.env.HOME, '.claude/plugins/installed_plugins.json'), 'utf8'));

// Get all plugin dirs
const pluginsDir = path.join(process.env.HOME, '.claude/plugins/marketplaces/claude-code-workflows/plugins');
const dirs = fs.readdirSync(pluginsDir).filter(d => fs.statSync(path.join(pluginsDir, d)).isDirectory());

// Add each as a plugin
dirs.forEach(name => {
  const key = name + '@claude-code-workflows';
  existing.plugins[key] = [{
    scope: 'user',
    installPath: 'C:\\\\Users\\\\User\\\\.claude\\\\plugins\\\\marketplaces\\\\claude-code-workflows\\\\plugins\\\\' + name,
    version: '1.0.0',
    installedAt: '$NOW',
    lastUpdated: '$NOW',
    gitCommitSha: '$COMMIT'
  }];
});

fs.writeFileSync(path.join(process.env.HOME, '.claude/plugins/installed_plugins.json'), JSON.stringify(existing, null, 2));
console.log('Written ' + dirs.length + ' new plugins. Total: ' + Object.keys(existing.plugins).length);
"
```

Run this script to update the file.

